final:
module top_module(ovf, b, eq, obf_leds);input ovf, b, eq;
output [2:0] obf_leds;

reg [2:0] obf_leds;

always @(ovf, b, eq)
begin
    if(ovf)
        obf_leds[0] = 1;
    else
        obf_leds[0] = 0;

    if(b)
        obf_leds[1] = 1;
    else
        obf_leds[1] = 0;

    if(eq)
        obf_leds[2] = 1;
    else
        obf_leds[2] = 0;
end
endmodule
